"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { Eye, EyeOff, Mail, Lock, ShieldCheck } from "lucide-react";

const ADMIN_EMAIL = "admin@aurora.test";
const ADMIN_PASSWORD = "Admin@123";

export default function AdminLoginPage() {
  const router = useRouter();
  const { loginAsAdmin } = useAuth();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    if (!email || !password) {
      setError("Please enter your credentials.");
      return;
    }

    setLoading(true);
    await new Promise((r) => setTimeout(r, 700));

    if (email === ADMIN_EMAIL && password === ADMIN_PASSWORD) {
      loginAsAdmin();
      router.push("/orders");
    } else {
      setLoading(false);
      setError("Invalid admin credentials. Please try again.");
    }
  };

  return (
    <div className="login-page">
      {/* Ambient glow blobs — shifted hue for admin */}
      <div className="login-blob login-blob-1" style={{ filter: "hue-rotate(20deg)" }} />
      <div className="login-blob login-blob-2" style={{ filter: "hue-rotate(20deg)" }} />

      <motion.div
        initial={{ opacity: 0, y: 28 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7, ease: "easeOut" }}
        className="login-card"
      >
        {/* Admin badge */}
        <div className="login-admin-badge">
          <ShieldCheck size={13} />
          <span>Administration Portal</span>
        </div>

        {/* Logo */}
        <div className="login-logo">
          <div className="login-logo-circle">
            <ShieldCheck size={22} color="var(--color-gold)" />
          </div>
          <div>
            <p className="login-brand">Aurora Dining</p>
            <p className="login-brand-sub">Admin Access</p>
          </div>
        </div>

        {/* Divider */}
        <div className="login-divider" />

        {/* Heading */}
        <div className="login-header">
          <p className="login-eyebrow">Restricted Area</p>
          <h1 className="login-title">Admin Login</h1>
          <p className="login-subtitle">
            Access the orders dashboard and reservations
          </p>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="login-form" noValidate>
          {/* Email */}
          <div className="login-field">
            <label className="login-label">Admin Email</label>
            <div className="login-input-wrap">
              <Mail size={15} className="login-input-icon" />
              <input
                id="admin-email"
                type="email"
                autoComplete="email"
                placeholder="admin@aurora.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="login-input"
              />
            </div>
          </div>

          {/* Password */}
          <div className="login-field">
            <label className="login-label">Admin Password</label>
            <div className="login-input-wrap">
              <Lock size={15} className="login-input-icon" />
              <input
                id="admin-password"
                type={showPw ? "text" : "password"}
                autoComplete="current-password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="login-input"
              />
              <button
                type="button"
                onClick={() => setShowPw(!showPw)}
                className="login-pw-toggle"
                aria-label="Toggle password visibility"
              >
                {showPw ? <EyeOff size={15} /> : <Eye size={15} />}
              </button>
            </div>
          </div>

          {/* Error */}
          {error && (
            <motion.p
              initial={{ opacity: 0, y: -6 }}
              animate={{ opacity: 1, y: 0 }}
              className="login-error"
            >
              {error}
            </motion.p>
          )}

          {/* Submit */}
          <motion.button
            type="submit"
            disabled={loading}
            whileHover={{ scale: loading ? 1 : 1.02 }}
            whileTap={{ scale: loading ? 1 : 0.98 }}
            className="login-btn"
          >
            {loading ? (
              <span className="login-spinner" />
            ) : (
              "Access Dashboard"
            )}
          </motion.button>
        </form>

        {/* Footer note */}
        <p className="login-note">
          Customer?{" "}
          <Link href="/login" className="login-link">
            Customer Login →
          </Link>
        </p>

        <div className="login-divider" style={{ marginTop: "28px" }} />
        <p className="login-hint">
          🔒 &nbsp;Demo credentials: admin@aurora.com / admin123
        </p>
      </motion.div>
    </div>
  );
}
